public boolean canPartitionKSubsets(int[] nums, int k) {
  int sum = 0;
  for (int num : nums) sum += num;
  if (sum % k != 0) return false;
  int target = sum / k;
  boolean[] visited = new boolean[nums.length];
  return dfs(nums, visited, 0, target, 0, k);
}

